class Solution:
    def minFallingPathSum(self, grid) -> int:
        n = len(grid)
        dp = grid[0][:]
        for r in range(1, n):
            new_dp = []
            for c in range(n):
                new_dp.append(grid[r][c] + min(dp[j] for j in range(n) if j != c))
            dp = new_dp
        return min(dp)

