class Solution:
    def minFallingPathSum(self, grid) -> int:
        n = len(grid)
        dp = grid[0][:]
        for r in range(1, n):
            # find best and second-best in dp
            best1_val, best2_val = float('inf'), float('inf')
            best1_col = -1
            for c, v in enumerate(dp):
                if v < best1_val:
                    best2_val = best1_val
                    best1_val, best1_col = v, c
                elif v < best2_val:
                    best2_val = v
            new_dp = []
            for c in range(n):
                prev = best1_val if c != best1_col else best2_val
                new_dp.append(grid[r][c] + prev)
            dp = new_dp
        return min(dp)

