var minFallingPathSum = function(grid) {
    const n = grid.length;
    let dp = grid[0].slice();
    for (let r = 1; r < n; r++) {
        let b1v = Infinity, b2v = Infinity, b1c = -1;
        for (let c = 0; c < n; c++) {
            if (dp[c] < b1v) { b2v = b1v; b1v = dp[c]; b1c = c; }
            else if (dp[c] < b2v) { b2v = dp[c]; }
        }
        const ndp = [];
        for (let c = 0; c < n; c++) {
            ndp.push(grid[r][c] + (c !== b1c ? b1v : b2v));
        }
        dp = ndp;
    }
    return Math.min(...dp);
};
